-- StarWind station placement (phase 9.2), generated by
-- cmd/starwind-tools/convert-map. Replaces the stub station seed (0004)
-- and its market (0007, owner_kind 2/4) with the full dump: 885 stations
-- / 10 shipyards / 48 trade_stations, all NPC-owned (owner_id NULL).
-- Pirbase market (owner_kind 5) and slaves (0027) are kept. Do not edit
-- by hand — rerun the converter.

DELETE FROM station_goods WHERE owner_kind IN (2, 4);
DELETE FROM trade_stations;
DELETE FROM shipyards;
DELETE FROM stations;




-- Keep the BIGSERIAL sequences past the imported ids.
SELECT setval('stations_id_seq',       (SELECT MAX(id) FROM stations));
SELECT setval('shipyards_id_seq',      (SELECT MAX(id) FROM shipyards));
SELECT setval('trade_stations_id_seq', (SELECT MAX(id) FROM trade_stations));

